import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
import { useEffect, useRef, useState } from 'react';

function Detail({ item, onClose }: { item: Item; onClose: () => void }) {
  const reduced = useReducedMotion();
  const titleRef = useRef<HTMLHeadingElement>(null);
  const previousFocus = useRef<HTMLElement | null>(null);

  useEffect(() => {
    previousFocus.current = document.activeElement as HTMLElement | null;
    titleRef.current?.focus();
    const onKey = (event: KeyboardEvent) => { if (event.key === 'Escape') onClose(); };
    document.addEventListener('keydown', onKey);
    return () => { document.removeEventListener('keydown', onKey); previousFocus.current?.focus(); };
  }, [onClose]);

  return (
    <motion.div
      role="dialog"
      aria-modal="true"
      aria-labelledby={`detail-title-${item.id}`}
      layoutId={reduced ? undefined : `card-${item.id}`}
      initial={reduced ? { opacity: 0 } : false}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      transition={{ duration: reduced ? 0.01 : 0.2, type: reduced ? false : 'spring', stiffness: 300, damping: 30 }}
      className="fixed inset-4 bg-white rounded-lg shadow-2xl p-8 z-50"
    >
      <motion.h1 id={`detail-title-${item.id}`} ref={titleRef} tabIndex={-1} layoutId={reduced ? undefined : `title-${item.id}`}>{item.title}</motion.h1>
      <motion.img layoutId={reduced ? undefined : `image-${item.id}`} src={item.image} alt="" />
      <button type="button" onClick={onClose}>Close</button>
    </motion.div>
  );
}

export function Gallery({ items }: { items: Item[] }) {
  const [selected, setSelected] = useState<Item | null>(null);
  return (
    <>
      {items.map((item) => <button key={item.id} type="button" onClick={() => setSelected(item)}>{item.title}</button>)}
      <AnimatePresence>{selected && <Detail item={selected} onClose={() => setSelected(null)} />}</AnimatePresence>
    </>
  );
}

