        >
          {item.label}
        </Reorder.Item>
      ))}
    </Reorder.Group>
  );
}

import {useEffect, useRef} from 'react';
import gsap from 'gsap';
import {ScrollTrigger} from 'gsap/ScrollTrigger';
gsap.registerPlugin(ScrollTrigger);

export function HorizontalScroll({panels}: {panels: React.ReactNode[]}) {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (!ref.current) return;
    if (matchMedia('(prefers-reduced-motion: reduce)').matches) return;
    const panelsEl = ref.current.querySelector('.panels') as HTMLElement;
    const totalWidth = panelsEl.scrollWidth - window.innerWidth;
    const tween = gsap.to(panelsEl, {
      x: -totalWidth,
      ease: 'none',
      scrollTrigger: {
        trigger: ref.current,
        start: 'top top',
        end: () => `+=${totalWidth}`,
        pin: true,
        scrub: 1,
        invalidateOnRefresh: true
      }
    });
    return () => { tween.scrollTrigger?.kill(); tween.kill(); };
  }, []);
  return (
    <div ref={ref} className="h-screen overflow-hidden">
      <div className="panels flex h-full">
        {panels.map((p, i) => <div key={i} className="min-w-full h-full">{p}</div>)}
      </div>
    </div>
  );
}

import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, interpolate, Extrapolate, runOnJS} from 'react-native-reanimated';
import {AccessibilityInfo, StyleSheet, View, Text} from 'react-native';
import {useEffect, useState} from 'react';

const THRESHOLD = 80;

export function PullToRefresh({onRefresh, children}: {onRefresh: () => Promise<void>; children: React.ReactNode}) {
  const offset = useSharedValue(0);
  const [reducedMotion, setReducedMotion] = useState(false);
  useEffect(() => {
    AccessibilityInfo.isReduceMotionEnabled().then(setReducedMotion);
  }, []);

  function triggerRefresh() {
    onRefresh().finally(() => {
      offset.value = withSpring(0);
    });
  }

  const pan = Gesture.Pan()
    .onUpdate((e) => {
      // rubber-band: translation grows slower as you pull
      offset.value = Math.max(0, e.translationY * 0.5);
    })
    .onEnd(() => {
      if (offset.value > THRESHOLD) {
        offset.value = withSpring(THRESHOLD * 1.2);
        runOnJS(triggerRefresh)();
      } else {
        offset.value = withSpring(0);
      }
    });

  const containerStyle = useAnimatedStyle(() => ({transform: [{translateY: offset.value}]}));
  const indicatorStyle = useAnimatedStyle(() => ({
    opacity: interpolate(offset.value, [0, THRESHOLD], [0, 1], Extrapolate.CLAMP)
  }));

  if (reducedMotion) return <>{children}</>;

  return (
    <GestureDetector gesture={pan}>
      <Animated.View style={[styles.container, containerStyle]}>
        <Animated.View style={[styles.indicator, indicatorStyle]}>
          <Text>Pull to refresh</Text>
        </Animated.View>
        {children}
      </Animated.View>
    </GestureDetector>
  );
}

