import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withTiming, runOnJS, interpolate} from 'react-native-reanimated';
import {Dimensions} from 'react-native';

const {width} = Dimensions.get('window');
const THRESHOLD = width * 0.4;
const VEL_THRESHOLD = 800;

export function SwipeCard({onCommit}: {onCommit: (dir: 'left' | 'right') => void}) {
  const x = useSharedValue(0);
  const pan = Gesture.Pan()
    .onUpdate((e) => { x.value = e.translationX; })
    .onEnd((e) => {
      const past = Math.abs(x.value) > THRESHOLD;
      const fast = Math.abs(e.velocityX) > VEL_THRESHOLD;
      if (past || fast) {
        const dir = x.value > 0 ? 'right' : 'left';
        x.value = withTiming(dir === 'right' ? width * 1.5 : -width * 1.5, {duration: 250}, () => {
          runOnJS(onCommit)(dir);
        });
      } else {
        x.value = withSpring(0);
      }
    });
  const style = useAnimatedStyle(() => ({
    transform: [{translateX: x.value}, {rotate: `${interpolate(x.value, [-width, width], [-30, 30])}deg`}]
  }));
  return (
    <GestureDetector gesture={pan}>
      <Animated.View style={[{width: 300, height: 400, backgroundColor: 'white'}, style]}/>
    </GestureDetector>
  );
}

