import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring} from 'react-native-reanimated';
import {Dimensions} from 'react-native';

const {height} = Dimensions.get('window');
const SNAP = [0.9, 0.5, 0.2]; // closed, half, full

export function BottomSheet({children}: {children: React.ReactNode}) {
  const y = useSharedValue(height * 0.9);
  const start = useSharedValue(0);
  const pan = Gesture.Pan()
    .onBegin(() => { start.value = y.value; })
    .onUpdate((e) => { y.value = Math.max(height * 0.1, start.value + e.translationY); })
    .onEnd((e) => {
      const target = SNAP.map(p => p * height).reduce((nearest, candidate) => 
        Math.abs(y.value + e.velocityY * 0.3 - candidate) < Math.abs(y.value + e.velocityY * 0.3 - nearest) ? candidate : nearest);
      y.value = withSpring(target, {damping: 25, stiffness: 200});
    });
  const style = useAnimatedStyle(() => ({transform: [{translateY: y.value}]}));
  return (
    <GestureDetector gesture={pan}>
      <Animated.View style={[{position: 'absolute', left: 0, right: 0, top: 0, height, backgroundColor: 'white', borderTopLeftRadius: 16, borderTopRightRadius: 16}, style]}>
        <View style={{width: 40, height: 4, backgroundColor: '#ccc', borderRadius: 2, alignSelf: 'center', marginTop: 8}}/>
        {children}
      </Animated.View>
    </GestureDetector>
  );
}

